import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [stats, setStats] = useState({ totalBookings: 0, activeBookings: 0, totalSlots: 0, revenue: 0, totalUsers: 0 });
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchAdminData = async () => {
      try {
        const role = localStorage.getItem("role");
        if (role !== "admin") {
          navigate("/");
          return;
        }

        const statsRes = await axios.get("/admin/stats");
        setStats(statsRes.data);

        const bookingsRes = await axios.get("/admin/bookings");
        setBookings(bookingsRes.data);

        setLoading(false);
      } catch (err) {
        console.error("Admin Access Error", err);
        navigate("/");
      }
    };
    fetchAdminData();
  }, [navigate]);

  if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Loading Admin Dashboard...</div>;

  return (
    <div style={{ padding: "40px", maxWidth: "1200px", margin: "0 auto", minHeight: "80vh" }}>
      <h1 style={{ color: "var(--accent-cyan)", borderBottom: "1px solid rgba(255,255,255,0.1)", paddingBottom: "15px", textShadow: "var(--shadow-neon-cyan)", letterSpacing: "3px" }}>COMMAND CENTER 🛡️</h1>

      {/* Stats Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: "25px", marginTop: "30px" }}>
        <StatCard title="TOTAL ENTITIES" value={stats.totalUsers} icon="👥" color="var(--accent-cyan)" />
        <StatCard title="ACTIVE SESSIONS" value={stats.activeBookings} icon="⚡" color="var(--accent-green)" />
        <StatCard title="NETWORK SLOTS" value={stats.totalSlots} icon="🅿️" color="var(--accent-yellow)" />
        <StatCard title="CREDIT REVENUE" value={`$${stats.revenue}`} icon="💠" color="var(--accent-pink)" />
      </div>

      {/* Bookings Table */}
      <h2 style={{ marginTop: "50px", color: "var(--text-secondary)", letterSpacing: "2px" }}>SYSTEM LOGS</h2>
      <div style={{ overflowX: "auto", background: "var(--glass-bg)", borderRadius: "20px", boxShadow: "0 20px 40px rgba(0,0,0,0.5)", border: "1px solid rgba(255,255,255,0.05)", backdropFilter: "var(--glass-blur)" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "rgba(0,0,0,0.4)", textAlign: "left" }}>
              <th style={thStyle}>ENTITY</th>
              <th style={thStyle}>VEHICLE_ID</th>
              <th style={thStyle}>SECTOR</th>
              <th style={thStyle}>BAY</th>
              <th style={thStyle}>TIMEFRAME</th>
              <th style={thStyle}>STATE</th>
            </tr>
          </thead>
          <tbody>
            {bookings.map(b => (
              <tr key={b._id} style={{ borderBottom: "1px solid rgba(255,255,255,0.05)", transition: "var(--transition)", hover: { background: "rgba(255,255,255,0.02)" } }}>
                <td style={tdStyle}>
                  <div style={{ color: "var(--text-primary)", fontWeight: "bold" }}>{b.userId?.name || "Unknown"}</div>
                  <div style={{ fontSize: "0.8em", color: "var(--text-secondary)" }}>{b.userId?.email}</div>
                </td>
                <td style={tdStyle}>{b.vehicleNumber || "N/A"}</td>
                <td style={tdStyle}>{b.slotId?.parkingLotId?.name || "Unknown"}</td>
                <td style={tdStyle}>{b.slotId?.slotNumber || "N/A"}</td>
                <td style={tdStyle}>
                  <div style={{ color: "var(--text-secondary)" }}>{new Date(b.startTime).toLocaleDateString()}</div>
                  <div style={{ fontSize: "0.8em", color: "var(--accent-cyan)" }}>{new Date(b.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(b.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                </td>
                <td style={tdStyle}>
                  <span style={{
                    padding: "6px 12px", borderRadius: "10px", fontSize: "0.8em", fontWeight: "bold",
                    background: b.status === "Booked" || b.status === "Active" ? "rgba(0, 255, 136, 0.1)" : "rgba(255, 42, 95, 0.1)",
                    color: b.status === "Booked" || b.status === "Active" ? "var(--accent-green)" : "var(--accent-pink)",
                    border: b.status === "Booked" || b.status === "Active" ? "1px solid var(--accent-green)" : "1px solid var(--accent-pink)"
                  }}>
                    {b.status.toUpperCase()}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const StatCard = ({ title, value, icon, color }) => (
  <div style={{ background: "var(--glass-bg)", padding: "25px", borderRadius: "20px", boxShadow: "0 10px 30px rgba(0,0,0,0.3)", borderTop: `2px solid ${color}`, backdropFilter: "var(--glass-blur)", position: "relative", overflow: "hidden" }}>
    <div style={{ position: "absolute", top: "-20px", right: "-20px", fontSize: "6em", opacity: "0.05", color: "white" }}>{icon}</div>
    <div style={{ fontSize: "2.5em", float: "right", color }}>{icon}</div>
    <div style={{ color: "var(--text-secondary)", fontSize: "0.85em", letterSpacing: "2px", textTransform: "uppercase", marginBottom: "10px" }}>{title}</div>
    <div style={{ fontSize: "2.5em", fontWeight: "bold", color: "var(--text-primary)", textShadow: `0 0 15px ${color}` }}>{value}</div>
  </div>
);

const thStyle = { padding: "20px 15px", color: "var(--text-secondary)", fontSize: "0.85em", textTransform: "uppercase", letterSpacing: "2px", borderBottom: "1px solid rgba(255,255,255,0.1)" };
const tdStyle = { padding: "15px", color: "var(--text-primary)" };
